export const 鎮宅奴馬 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.4 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    // 符頭：桿一
    線(p => p.M(X(1.0), Z(1.2)).L(X(6.2), Z(1.1)));
    圈(0.7, 1.2);
    圈(6.5, 1.1);
    // 次桿短（左散圈）
    圈(0.7, 2.2);
    線(p => p.M(X(1.7), Z(2.1)).L(X(5.6), Z(2.0)));
    圈(1.4, 2.1);
    圈(5.9, 2.0);
    // 左圈杙垂
    圈(1.6, 3.2);
    連([1.6, 3.2], [1.6, 5.6]);
    圈(1.6, 5.6);
    // 冂形連圈框（隅圈＋上桁右柱）
    圈(2.7, 3.3);
    連([2.7, 3.3], [5.2, 3.2]);
    圈(5.2, 3.2);
    連([5.2, 3.2], [5.2, 5.4]);
    圈(5.2, 5.4);
    // 框內圈列三＋底散圈
    圈(4.0, 3.9);
    圈(4.0, 4.7);
    圈(4.0, 5.5);
    圈(2.8, 5.9);
    // 右緣圈列四
    圈(6.6, 2.4);
    圈(6.7, 3.4);
    圈(6.8, 4.4);
    圈(6.9, 5.4);
    // 三柱箱陣：頂桁
    線(p => p.M(X(0.8), Z(7.2)).L(X(6.8), Z(7.1)), 0.42);
    // 左柱目箱三疊
    const 目 = (x0, x1, z0, z1) => {
        線(p => p.M(X(x0), Z(z0)).L(X(x0), Z(z1)).L(X(x1), Z(z1 - 0.05))
            .L(X(x1), Z(z0 - 0.05)).L(X(x0 - 0.05), Z(z0)));
        線(p => p.M(X(x0 + 0.1), Z((z0 + z1) / 2)).L(X(x1 - 0.1), Z((z0 + z1) / 2 - 0.03)), 0.32);
    };
    目(0.8, 3.2, 7.9, 10.0);
    目(0.8, 3.2, 10.6, 12.7);
    目(0.8, 3.2, 13.3, 15.4);
    // 中三軌
    線(p => p.M(X(3.55), Z(7.28)).L(X(3.53), Z(15.5)), 0.34);
    線(p => p.M(X(3.85), Z(7.26)).L(X(3.83), Z(15.48)), 0.34);
    線(p => p.M(X(4.15), Z(7.24)).L(X(4.13), Z(15.45)), 0.34);
    // 右柱目箱三疊
    目(4.5, 6.8, 7.9, 10.0);
    目(4.5, 6.8, 10.6, 12.7);
    目(4.5, 6.8, 13.3, 15.4);
    // 軌末雙圈小結
    圈(3.85, 16.0, 0.22);
    圈(3.85, 16.5, 0.22);
    // 底寬目二
    目(0.9, 6.7, 16.9, 18.0);
    目(0.9, 6.7, 18.35, 19.15);
};
